import { getSizeInMemoryOfString } from '../utils/fs';
import { NordicAssetCacheLimitError } from './error/asset-exceeds-cache-limit';
import { CACHE_MEMORY_LIMIT } from './constants';

export class LimitedStringMap extends Map<string, string> {
  #mapMemorySize = 0;

  set(key: string, value: string) {
    if (__DEV__) {
      return super.set(key, value);
    }

    const entrySize = getSizeInMemoryOfString(key + value);

    if (entrySize > CACHE_MEMORY_LIMIT) {
      throw new NordicAssetCacheLimitError(key);
    }

    // Delete first entry until cache is not exceeded anymore
    while (CACHE_MEMORY_LIMIT < this.#mapMemorySize + entrySize && this.size) {
      const [firstElementKey, firstElementValue] = this.entries().next().value!;
      const firstElementSize = getSizeInMemoryOfString(
        firstElementKey + firstElementValue,
      );

      this.delete(firstElementKey);

      this.#mapMemorySize -= firstElementSize;
    }

    this.#mapMemorySize += entrySize;

    return super.set(key, value);
  }
}
